<?php namespace App\Repositories\Payroll;use App\Repositories\BaseRepository;use App\Models\Payroll\LoanRequest;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class LoanRequestRepository extends BaseRepository{    public function __construct(LoanRequest $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findByLoanType(string $loanType): Collection    {        return $this->findByField('loan_type', $loanType);    }    public function getPendingRequests(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getApprovedLoans(): Collection    {        return $this->query()->where('status', 'approved')->get();    }    public function getByAmountRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('loan_amount', [$min, $max])->get();    }    public function approveLoan(int $id, ?string $approvedBy = null): bool    {        $data = ['status' => 'approved', 'approved_at' => now()];        if ($approvedBy) {            $data['approved_by'] = $approvedBy;        }        return $this->update($id, $data);    }    public function rejectLoan(int $id, string $reason): bool    {        return $this->update($id, ['status' => 'rejected', 'rejection_reason' => $reason]);    }    public function getEmployeeOutstandingLoans(int $employeeId): Collection    {        return $this->query()->where('employee_id', $employeeId)->whereIn('status', ['approved', 'disbursed'])->get();    }    public function getTotalOutstandingByEmployee(int $employeeId): float    {        return $this->query()->where('employee_id', $employeeId)->whereIn('status', ['approved', 'disbursed'])->sum('remaining_amount');    }}